"use strict";

const Constants = Object.freeze({
  /**
   * The CSS class of the annotation bubble
   * @type {String}
   */
  ANNOTATE_BUBBLE_CLASS: "annotation-bubble",
  /**
   * The name of the icon rendered in the popup
   * @type {String}
   */
  ANNOTATE_ICON_NAME: "comment",
  /**
   * The keyboard shortcut that needs to be triggered to create an annotation
   * @type {KeyboardEventInit}
   */
  ANNOTATE_SHORTCUT: { ctrlKey: true, code: "KeyM", key: "m", keyCode: 77 }, // shortcuts.js still expects the deprecated keyCode property
  /**
   * The translation key for the popup button title (for accessibility)
   * @type {String}
   */
  ANNOTATE_TRANSLATION_KEY: "action.create.submit.text",
  /**
   * The CSS class that needs to be added to show the popup
   * @type {String}
   */
  POPUP_CLASS_OPEN: "opened",
  /**
   * The element id of the popup
   * @type {String}
   */
  POPUP_ID: "annotation-popup"
});

// Icons API (see: https://extensions.xwiki.org/xwiki/bin/view/Extension/Icon%20Theme%20Application#HJavaScriptAPI)
define("xwiki-annotate-popup/icons", {
  icons: [Constants.ANNOTATE_ICON_NAME]
});

// Translation API (see: https://extensions.xwiki.org/xwiki/bin/view/Extension/Localization/#HFromJavaScript)
define("xwiki-annotate-popup/translation-keys", {
  prefix: "annotations.",
  keys: [Constants.ANNOTATE_TRANSLATION_KEY]
});

define("xwiki-annotate-popup", ["xwiki-icon!xwiki-annotate-popup/icons", "xwiki-l10n!xwiki-annotate-popup/translation-keys"], function(icons, l10n) {
   /**
    * Debounces a function
    * @param {Function} func
    * @param {number} delay - Delay time
    * @returns {Function} - Debounced version of func (result of the function is NOT returned at all)
    */
   function debounce(func, delay) {
      let timeout;
      return function (...args) {
          clearTimeout(timeout);
          timeout = setTimeout(() => { func.apply(this, args); }, delay);
      };
   }

   const annotateTriggerEvent = new KeyboardEvent("keydown", Constants.ANNOTATE_SHORTCUT);

   // TODO: use private class fields and method once Google Closure Compiler supports it (see: https://github.com/google/closure-compiler/issues/4286)
   class AnnotatePopup {
      /**
       * The page container
       * @type {HTMLElement}
       */
      wikiContent = null;
      /**
       * The popup container element
       * @type {HTMLElement}
       */
      popup = null;
      /**
       * The popup button
       * @type {HTMLElement}
       */
      annotateButton = null;
      /**
       * The last focussed element before focus was set programmatically (see this.open())
       * @type {HTMLElement}
       */
      previousFocusElem = null;

      /**
       * @param {HTMLElement} wikiContent - The page container
       */
      constructor(wikiContent) {
         this.wikiContent = wikiContent;

         this._onSelection = debounce(this._onSelection.bind(this), 700);
         this._onEscapeKey = this._onEscapeKey.bind(this);
         this._onButtonClick = debounce(this._onButtonClick.bind(this), 75);
         this._onClickAway = this._onClickAway.bind(this);
         this._onViewportChange = debounce(this._onViewportChange.bind(this), 75);

         this._create();
         this._registerListeners();
      }

      /**
       * Insert the popup to DOM
       */
      _create() {
         this.popup = document.createElement("div");
         this.popup.id = Constants.POPUP_ID;
         this.popup.setAttribute("role", "toolbar");
         this.popup.setAttribute("aria-hidden", "true");

         this.popupButton = document.createElement("button");
         this.popupButton.classList.add("btn", "btn-default", "btn-xs");
         this.popupButton.title = l10n[Constants.ANNOTATE_TRANSLATION_KEY];
         this.popupButton.setAttribute("aria-label", l10n[Constants.ANNOTATE_TRANSLATION_KEY]);

         this.popupButton.appendChild(icons[Constants.ANNOTATE_ICON_NAME].render());
         this.popup.appendChild(this.popupButton);
         document.body.appendChild(this.popup);
      }

      /**
       * Open the popup near the selected text range
       * @param {Selection} selection - A selection
       */
      open(selection) {
         if(document.getElementsByClassName(Constants.ANNOTATE_BUBBLE_CLASS).length !== 0) {
           // an annotate bubble is opened already
           return;
         }

         const { top, left } = this._getPositioning(selection);
         this.popup.style.top = top;
         this.popup.style.left = left;

         this.popup.classList.add(Constants.POPUP_CLASS_OPEN);
         this.popup.setAttribute("aria-hidden", "false");

         // focus popup button
         this.previousFocusElem = document.activeElement;
         this.popupButton.focus();

         document.addEventListener("click", this._onClickAway);
         if(window.visualViewport) window.visualViewport.addEventListener("resize", this._onViewportChange, { passive: true }); // re-positioning on resize/zoom
      }

      /**
       * Close the popup
       */
      close() {
          // restore focus
          if (this.previousFocusElem &&
             document.contains(this.previousFocusElem) &&
             typeof this.previousFocusElem.focus === "function" &&
             !this.previousFocusElem.hasAttribute("disabled") &&
             this.previousFocusElem.getClientRects().length) {
           this.previousFocusElem.focus();
         } else {
            // this might not be the most accessible way
            this.popupButton.blur();
         }
         this.popup.classList.remove(Constants.POPUP_CLASS_OPEN);
         this.popup.setAttribute("aria-hidden", "true");

         document.removeEventListener("click", this._onClickAway);
         if(window.visualViewport) window.visualViewport.removeEventListener("resize", this._onViewportChange);
      }

      /**
       * Register event listeners
       */
      _registerListeners() {
         this.popupButton.addEventListener("click", this._onButtonClick, { passive: true });
         this.popupButton.addEventListener("keydown", this._onEscapeKey, { passive: true }); // exit when pressing Escape

         // open popup on text selection, disable in edit mode
         document.addEventListener("selectionchange", this._onSelection, { passive: true });
         this.wikiContent.addEventListener("xwiki:actions:edit", () => { document.removeEventListener("selectionchange", this._onSelection); });
         this.wikiContent.addEventListener("xwiki:actions:view", () => { document.addEventListener("selectionchange", this._onSelection, { passive: true }); });

         // prevent losing focus (the selection) when clicking on popup edges
         this.popup.addEventListener("pointerdown", (event) => { event.preventDefault(); }, { passive: false });
      }

      /**
       * Event handler for popup button click
       */
      _onButtonClick() {
         this.close();
         document.dispatchEvent(annotateTriggerEvent);
      }

      /*
       * Event handler for a page click (popup click away listener)
       * @param {PointerEvent} event
       */
      _onClickAway(event) {
        if(!this.popup.contains(event.target)) {
           this.close();
        }
      }

      /**
       * Event handler for document selection. Checks the current selection and opens the popup
       */
      _onSelection() {
         const selection = document.getSelection();
         if (!selection || !this.wikiContent.contains(selection.anchorNode) || !selection.toString().trim()) {
             // selection invalid or not in document content
             return;
         }

         this.open(selection);
      }

      /**
       * Event handler for popup button keydown. Closes popup on Escape key press
       * @param {KeyboardEvent} event
       */
      _onEscapeKey(event) {
         if(event.key === "Escape") {
            this.close();
         }
      }

      /**
       * Event handler for window resize/zoom. Recalculates the positioning of the popup
       */
      _onViewportChange(event) {
         const { top, left } = this._getPositioning(document.getSelection());
         requestAnimationFrame(() => {
            this.popup.style.top = top;
            this.popup.style.left = left;
         });
      }

      /**
       * Get popup positioning (top and left absolute positioning)
       * @param {Selection} selection - A selection
       * @return {{top: number, left: number}} The popup element and popup button
       */
      _getPositioning(selection) {
         if(!selection || selection.rangeCount === 0) {
            // invalid selection
            return;
         }

         // use last rectangle of selection, important for correct positioning in multi-line selections
         const rects = selection.getRangeAt(0).getClientRects();
         if (!rects.length) {
            // empty collection
            return;
         }
         const rect = rects[rects.length - 1];

         return {
          top: (rect.top + window.scrollY - this.popup.offsetHeight - 4) + "px",
          left: (rect.left + window.scrollX + rect.width - (this.popup.offsetWidth / 2)) + "px"
         };
      }
   }

   return AnnotatePopup;
});

#annotation-popup {
   position: absolute;
   background-color: var(--xwiki-page-content-bg);
   padding: 4px;
   border-radius: 4px;
   box-shadow: 0 1.65px 3px var(--btn-default-border);
   visibility: hidden;
   opacity: 0;
   transition: opacity .2s ease-in;
   &.opened {
      visibility: visible;
      opacity: 1;
   }
}
